#include <bits/stdc++.h>
using namespace std;

int main() {
    int a, b, maxn = pow(10, 9);
    long long ans;
    cin >> a >> b;
    ans = a;
    for (int i = 1; i < b; i++) {
        ans *= a;
        if (ans > maxn) {
            cout << -1;
            return 0;
        }
    }
    cout << ans;
    return 0;
}
